const { BREP } = api;

// === Dimensions ===
const flangeOD = 80;          // flange outer diameter
const flangeR = flangeOD / 2; // 40
const flangeThickness = 10;   // flange disk thickness

const pipeOD = 40;            // pipe outer diameter
const pipeR = pipeOD / 2;     // 20
const pipeLen = 50;           // pipe length above flange (rises from z=10 to z=60)

const boreID = 28;            // central bore inner diameter
const boreR = boreID / 2;     // 14

const boltCount = 6;
const boltD = 8;
const boltR = boltD / 2;
const pitchR = 32;            // bolt circle radius (64 mm pitch diameter)

// === Build the solid body (flange disk + pipe), fillet/chamfer FIRST, cut LAST ===

// Flange disk: lies on XY, from z=0 to z=flangeThickness (10).
const flangeDisk = BREP.label(BREP.cylinder(flangeR, flangeThickness), 'flange', { color: '#4a78b5' });

// Pipe: starts at top of flange (z=10), rises to z=10+50 = 60.
const pipe = BREP.label(BREP.cylinder(pipeR, pipeLen).translate([0, 0, flangeThickness]), 'flange', { color: '#4a78b5' });

// Fuse flange + pipe.
let body = flangeDisk.fuse(pipe);

// Fillet the neck where the pipe meets the flange disk (at z=10).
// The shared circular edge sits at world z=10. Use a tight z-band.
body = body.fillet(2.5, { minZ: flangeThickness - 0.01, maxZ: flangeThickness + 0.01 });

// Chamfer the top rim of the pipe (face end at z = flangeThickness + pipeLen = 60).
const topZ = flangeThickness + pipeLen;
body = body.chamfer(1.0, { minZ: topZ - 0.01, maxZ: topZ + 0.01 });

// Chamfer the outer bottom rim of the flange (z=0).
body = body.chamfer(0.8, { minZ: -0.01, maxZ: 0.01 });

// === Now cut the holes ===

// Central bore: through pipe + flange (overshoot both ends by a hair).
const bore = BREP.cylinder(boreR, topZ + 2).translate([0, 0, -1]);

// Bolt holes through the flange disk only (overshoot disk thickness).
const boltHoles = [];
for (let i = 0; i < boltCount; i++) {
  const angle = (i * 360) / boltCount;
  const rad = (angle * Math.PI) / 180;
  const x = pitchR * Math.cos(rad);
  const y = pitchR * Math.sin(rad);
  const hole = BREP.cylinder(boltR, flangeThickness + 2).translate([x, y, -1]);
  boltHoles.push(hole);
}

return BREP.cutAll([body, bore, ...boltHoles]);
